    11â†’
    12â†’const defaultGitHubAPIURL = "https://api.github.com"
    13â†’
    14â†’// ghRelease represents a single release from the GitHub REST API.
    15â†’type ghRelease struct {
    16â†’	TagName     string `json:"tag_name"`
    17â†’	Body        string `json:"body"`
    18â†’	HTMLURL     string `json:"html_url"`
    19â†’	PublishedAt string `json:"published_at"`
    20â†’	Prerelease  bool   `json:"prerelease"`
    21â†’	Draft       bool   `json:"draft"`
    22â†’}
    23â†’
    24â†’// GitHubSource polls the GitHub REST API for repository releases.
    25â†’type GitHubSource struct {
    26â†’	client     *http.Client
    27â†’	repository string
    28â†’	baseURL    string
    29â†’	sourceID   string
    30â†’}
    31â†’
    32â†’func NewGitHubSource(client *http.Client, repository string, sourceID string) *GitHubSource {
    33â†’	return &GitHubSource{
    34â†’		client:     client,
    35â†’		repository: repository,
    36â†’		baseURL:    defaultGitHubAPIURL,
    37â†’		sourceID:   sourceID,
    38â†’	}
    39â†’}
    40â†’
    41â†’func (s *GitHubSource) Name() string    { return "github" }
    42â†’func (s *GitHubSource) SourceID() string { return s.sourceID }
    43â†’
    44â†’func (s *GitHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    45â†’	url := fmt.Sprintf("%s/repos/%s/releases?per_page=30", s.baseURL, s.repository)
    46â†’
    47â†’	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    48â†’	if err != nil {
    49â†’		return nil, fmt.Errorf("create request: %w", err)
    50â†’	}
    51â†’	req.Header.Set("Accept", "application/vnd.github+json")
    52â†’
    53â†’	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
    54â†’		req.Header.Set("Authorization", "Bearer "+token)
    55â†’	}
    56â†’
    57â†’	resp, err := s.client.Do(req)
    58â†’	if err != nil {
    59â†’		return nil, fmt.Errorf("fetch releases: %w", err)
    60â†’	}
    61â†’	defer resp.Body.Close()
    62â†’
    63â†’	if resp.StatusCode != http.StatusOK {
    64â†’		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
    65â†’	}
    66â†’
    67â†’	var releases []ghRelease
    68â†’	if err := json.NewDecoder(resp.Body).Decode(&releases); err != nil {
    69â†’		return nil, fmt.Errorf("decode releases: %w", err)
    70â†’	}
    71â†’
    72â†’	results := make([]IngestionResult, 0, len(releases))
    73â†’	for _, rel := range releases {
    74â†’		if rel.Draft {
    75â†’			continue
    76â†’		}
    77â†’		if rel.TagName == "" {
    78â†’			continue
    79â†’		}
    80â†’
    81â†’		ts, _ := time.Parse(time.RFC3339, rel.PublishedAt)
    82â†’
    83â†’		prerelease := "false"
    84â†’		if rel.Prerelease {
    85â†’			prerelease = "true"
    86â†’		}
    87â†’
    88â†’		results = append(results, IngestionResult{
    89â†’			Repository: s.repository,
    90â†’			RawVersion: rel.TagName,
    91â†’			Changelog:  rel.Body,
    92â†’			Metadata: map[string]string{
    93â†’				"release_url": rel.HTMLURL,
    94â†’				"prerelease":  prerelease,
    95â†’			},
    96â†’			Timestamp: ts,
    97â†’		})
    98â†’	}
    99â†’	return results, nil
   100â†’}
   101â†’

