     1â†’export function timeAgo(dateStr?: string | null): string {
     2â†’  if (!dateStr) return "\u2014";
     3â†’  const diff = Date.now() - new Date(dateStr).getTime();
     4â†’  const mins = Math.floor(diff / 60000);
     5â†’  if (mins < 60) return `${mins}m ago`;
     6â†’  const hrs = Math.floor(mins / 60);
     7â†’  if (hrs < 24) return `${hrs}h ago`;
     8â†’  return `${Math.floor(hrs / 24)}d ago`;
     9â†’}
