    11â†’export function validateRepository(provider: string, repo: string): string | null {
    12â†’  const trimmed = repo.trim();
    13â†’  if (!trimmed) return null;
    14â†’  if (provider === "github" && /^(https?:\/\/)?github\.com\//i.test(trimmed)) {
    15â†’    return "Use owner/repo format (e.g. ethereum/go-ethereum), not a full URL";
    16â†’  }
    17â†’  if (provider === "dockerhub" && /^(https?:\/\/)?hub\.docker\.com\//i.test(trimmed)) {
    18â†’    return "Use owner/image format (e.g. library/nginx), not a full URL";
    19â†’  }
    20â†’  if (provider === "ecr-public" && /^(https?:\/\/)?(gallery\.ecr\.aws|public\.ecr\.aws)\//i.test(trimmed)) {
    21â†’    return "Use alias/repo format (e.g. i6b2w2n6/op-node), not a full URL";
    22â†’  }
    23â†’  if (provider === "gitlab" && /^(https?:\/\/)?gitlab\.com\//i.test(trimmed)) {
    24â†’    return "Use owner/repo format (e.g. inkscape/inkscape), not a full URL";
    25â†’  }
    26â†’  if (/^https?:\/\//.test(trimmed)) {
    27â†’    return "Use owner/repo format, not a full URL";
    28â†’  }
    29â†’  return null;
    30â†’}
