  if (!release) {
    return (
      <div className="py-16 text-center">
        <p
          style={{
            fontFamily: "var(--font-fraunces)",
            fontStyle: "italic",
            fontSize: "15px",
            color: "#9ca3af",
          }}
        >
          Release not found
        </p>
      </div>
    );
